const drafts = $('Get Draft Kosztorysy').first().json || [];
const tenders = $('Get New Tenders').first().json || [];

const draftList = Array.isArray(drafts) ? drafts : (drafts.items || []);
const tenderList = Array.isArray(tenders) ? tenders : (tenders.items || []);

let msg = '📊 <b>Poranny raport Terra-OS</b>\n\n';

msg += `📋 <b>Kosztorysy draft (${draftList.length}):</b>\n`;
for (const k of draftList.slice(0, 5)) {
  msg += `  • ${k.nazwa || 'Bez nazwy'}\n`;
}
if (draftList.length > 5) msg += `  ... i ${draftList.length - 5} więcej\n`;

msg += `\n🔍 <b>Nowe przetargi (${tenderList.length}):</b>\n`;
for (const t of tenderList.slice(0, 5)) {
  const val = t.value_pln ? ` | ${Number(t.value_pln).toLocaleString('pl-PL')} PLN` : '';
  msg += `  • ${(t.title || '').slice(0, 60)}${val}\n`;
}
if (tenderList.length > 5) msg += `  ... i ${tenderList.length - 5} więcej\n`;

msg += '\n💡 <i>Wygenerowano automatycznie przez Terra-OS + n8n</i>';

return [{ json: { chatId: $env.TELEGRAM_CHAT_ID, text: msg } }];
